const groqResponse = $input.first().json;

let parsed;
try {
  const text = groqResponse.choices[0].message.content;
  parsed = JSON.parse(text);
} catch (e) {
  parsed = {
    categorias: ['outro'],
    valor_glicose: null,
    descricao_resumida: 'Não foi possível processar.',
    avaliacao: 'neutra',
    feedback_paciente: 'Desculpe, não consegui entender. Pode reformular?',
    xp_ganho: 2,
    detalhes_xp: [{ acao: 'Interação genérica', xp: 2 }],
    dados_extraidos: { glicose_mg_dl: null, alimentos: [], medicamentos: [], atividade_fisica: null, sintomas: [] },
    alerta_clinico: false,
    mensagem_alerta: null
  };
}

return [{ json: parsed }];
